INSERT INTO email_templates_i18n (id, template_id, locale, template_name, subject, content) VALUES
('71000000-0000-4000-8000-000000000001','70000000-0000-4000-8000-000000000001','tr','Randevu Onaylandı','Randevunuz onaylandı - {{consultant_name}}','<p>Merhaba {{customer_name}},</p><p>{{consultant_name}} ile {{appointment_date}} tarihinde saat {{appointment_time}} randevunuz onaylandı.</p><p>Not: {{decision_note}}</p><p>Görüşmenizde başarılar dileriz.</p>'),
('71000000-0000-4000-8000-000000000101','70000000-0000-4000-8000-000000000001','en','Booking Confirmed','Your booking is confirmed - {{consultant_name}}','<p>Hello {{customer_name}},</p><p>Your booking with {{consultant_name}} on {{appointment_date}} at {{appointment_time}} has been confirmed.</p><p>Note: {{decision_note}}</p><p>We wish you a meaningful session.</p>'),
('71000000-0000-4000-8000-000000000102','70000000-0000-4000-8000-000000000001','de','Buchung bestätigt','Ihre Buchung wurde bestätigt - {{consultant_name}}','<p>Hallo {{customer_name}},</p><p>Ihre Buchung mit {{consultant_name}} am {{appointment_date}} um {{appointment_time}} wurde bestätigt.</p><p>Notiz: {{decision_note}}</p><p>Wir wünschen Ihnen eine wertvolle Sitzung.</p>'),
('71000000-0000-4000-8000-000000000002','70000000-0000-4000-8000-000000000002','tr','Randevu Hatırlatması','Yaklaşan görüşme - {{consultant_name}}','<p>Merhaba {{customer_name}},</p><p>{{consultant_name}} ile {{appointment_date}} tarihinde saat {{appointment_time}} görüşmeniz yaklaşıyor.</p><p>Görüşmeye zamanında katılmayı unutmayın.</p>'),
('71000000-0000-4000-8000-000000000103','70000000-0000-4000-8000-000000000002','en','Booking Reminder','Upcoming session - {{consultant_name}}','<p>Hello {{customer_name}},</p><p>Your session with {{consultant_name}} on {{appointment_date}} at {{appointment_time}} is coming up.</p><p>Please remember to join on time.</p>'),
('71000000-0000-4000-8000-000000000104','70000000-0000-4000-8000-000000000002','de','Buchungserinnerung','Bevorstehende Sitzung - {{consultant_name}}','<p>Hallo {{customer_name}},</p><p>Ihre Sitzung mit {{consultant_name}} am {{appointment_date}} um {{appointment_time}} steht bevor.</p><p>Bitte denken Sie daran, pünktlich teilzunehmen.</p>'),
('71000000-0000-4000-8000-000000000003','70000000-0000-4000-8000-000000000003','tr','Ödeme Alındı','Ödemeniz başarıyla alındı','<p>Merhaba {{customer_name}},</p><p>{{amount}} {{currency}} tutarındaki ödemeniz başarıyla alındı.</p><p>Sipariş No: {{order_id}}</p>'),
('71000000-0000-4000-8000-000000000105','70000000-0000-4000-8000-000000000003','en','Payment Received','Your payment was received','<p>Hello {{customer_name}},</p><p>Your payment of {{amount}} {{currency}} was received successfully.</p><p>Order ID: {{order_id}}</p>'),
('71000000-0000-4000-8000-000000000106','70000000-0000-4000-8000-000000000003','de','Zahlung erhalten','Ihre Zahlung wurde erhalten','<p>Hallo {{customer_name}},</p><p>Ihre Zahlung über {{amount}} {{currency}} wurde erfolgreich erhalten.</p><p>Bestellnummer: {{order_id}}</p>'),
('71000000-0000-4000-8000-000000000004','70000000-0000-4000-8000-000000000004','tr','Randevu Kabul Edildi','Randevunuz kabul edildi','<p>Merhaba {{customer_name}},</p><p>{{consultant_name}} ile {{appointment_date}} tarihinde saat {{appointment_time}} randevunuz kabul edildi.</p><p>Not: {{decision_note}}</p>'),
('71000000-0000-4000-8000-000000000107','70000000-0000-4000-8000-000000000004','en','Booking Accepted','Your booking was accepted','<p>Hello {{customer_name}},</p><p>Your booking with {{consultant_name}} on {{appointment_date}} at {{appointment_time}} was accepted.</p><p>Note: {{decision_note}}</p>'),
('71000000-0000-4000-8000-000000000108','70000000-0000-4000-8000-000000000004','de','Buchung angenommen','Ihre Buchung wurde angenommen','<p>Hallo {{customer_name}},</p><p>Ihre Buchung mit {{consultant_name}} am {{appointment_date}} um {{appointment_time}} wurde angenommen.</p><p>Notiz: {{decision_note}}</p>'),
('71000000-0000-4000-8000-000000000005','70000000-0000-4000-8000-000000000005','tr','Randevu Reddedildi','Randevunuz reddedildi','<p>Merhaba {{customer_name}},</p><p>{{consultant_name}} ile {{appointment_date}} tarihinde saat {{appointment_time}} randevunuz reddedildi.</p><p>Sebep: {{decision_note}}</p><p>Başka bir danışmanla randevu alabilirsiniz.</p>'),
('71000000-0000-4000-8000-000000000109','70000000-0000-4000-8000-000000000005','en','Booking Rejected','Your booking was rejected','<p>Hello {{customer_name}},</p><p>Your booking with {{consultant_name}} on {{appointment_date}} at {{appointment_time}} was rejected.</p><p>Reason: {{decision_note}}</p><p>You can book another consultant whenever you like.</p>'),
('71000000-0000-4000-8000-00000000010a','70000000-0000-4000-8000-000000000005','de','Buchung abgelehnt','Ihre Buchung wurde abgelehnt','<p>Hallo {{customer_name}},</p><p>Ihre Buchung mit {{consultant_name}} am {{appointment_date}} um {{appointment_time}} wurde abgelehnt.</p><p>Grund: {{decision_note}}</p><p>Sie können jederzeit einen anderen Berater buchen.</p>'),
('71000000-0000-4000-8000-000000000006','70000000-0000-4000-8000-000000000006','tr','Randevu İptal Edildi','Randevunuz iptal edildi','<p>Merhaba {{customer_name}},</p><p>{{consultant_name}} ile {{appointment_date}} tarihinde saat {{appointment_time}} randevunuz iptal edildi.</p><p>Başka bir danışmanla randevu alabilirsiniz.</p>'),
('71000000-0000-4000-8000-00000000010b','70000000-0000-4000-8000-000000000006','en','Booking Cancelled','Your booking was cancelled','<p>Hello {{customer_name}},</p><p>Your booking with {{consultant_name}} on {{appointment_date}} at {{appointment_time}} was cancelled.</p><p>You can book another consultant whenever you like.</p>'),
('71000000-0000-4000-8000-00000000010c','70000000-0000-4000-8000-000000000006','de','Buchung storniert','Ihre Buchung wurde storniert','<p>Hallo {{customer_name}},</p><p>Ihre Buchung mit {{consultant_name}} am {{appointment_date}} um {{appointment_time}} wurde storniert.</p><p>Sie können jederzeit einen anderen Berater buchen.</p>'),
('71000000-0000-4000-8000-000000000007','70000000-0000-4000-8000-000000000007','tr','Hoş Geldiniz','{{site_name}} platformuna hoş geldiniz','<p>Merhaba {{user_name}},</p><p>{{site_name}} platformuna hoş geldiniz. {{user_email}} adresiyle hesabınız oluşturuldu.</p><p>Artık danışmanlarımızla kolayca randevu alabilirsiniz.</p>'),
('71000000-0000-4000-8000-00000000010d','70000000-0000-4000-8000-000000000007','en','Welcome','Welcome to {{site_name}}','<p>Hello {{user_name}},</p><p>Welcome to {{site_name}}. Your account was created with {{user_email}}.</p><p>You can now book sessions with our consultants.</p>'),
('71000000-0000-4000-8000-00000000010e','70000000-0000-4000-8000-000000000007','de','Willkommen','Willkommen bei {{site_name}}','<p>Hallo {{user_name}},</p><p>Willkommen bei {{site_name}}. Ihr Konto wurde mit {{user_email}} erstellt.</p><p>Sie können jetzt Sitzungen mit unseren Beratern buchen.</p>'),
('71000000-0000-4000-8000-000000000008','70000000-0000-4000-8000-000000000008','tr','Şifre Sıfırlama','{{site_name}} şifre sıfırlama isteği','<p>Merhaba,</p><p>{{site_name}} hesabınız için şifre sıfırlama isteği alındı. Aşağıdaki bağlantıyı kullanabilirsiniz:</p><p><a href="{{reset_link}}">Şifremi Sıfırla</a></p><p>Bu isteği siz yapmadıysanız bu e-postayı dikkate almayın.</p>'),
('71000000-0000-4000-8000-00000000010f','70000000-0000-4000-8000-000000000008','en','Password Reset','{{site_name}} password reset request','<p>Hello,</p><p>We received a password reset request for your {{site_name}} account. You can use the link below:</p><p><a href="{{reset_link}}">Reset my password</a></p><p>If you did not request this, you can ignore this email.</p>'),
('71000000-0000-4000-8000-000000000110','70000000-0000-4000-8000-000000000008','de','Passwort zurücksetzen','Passwort-Zurücksetzung für {{site_name}}','<p>Hallo,</p><p>Wir haben eine Anfrage zum Zurücksetzen des Passworts für Ihr {{site_name}} Konto erhalten. Sie können den folgenden Link verwenden:</p><p><a href="{{reset_link}}">Passwort zurücksetzen</a></p><p>Wenn Sie diese Anfrage nicht gestellt haben, können Sie diese E-Mail ignorieren.</p>'),
('71000000-0000-4000-8000-000000000009','70000000-0000-4000-8000-000000000009','tr','Anlık Görüşme Talebi','Anlık görüşme talebiniz var - {{customer_name}}','<p>Merhaba {{consultant_name}},</p><p><strong>{{customer_name}}</strong> sizinle <strong>hemen şimdi</strong> görüşmek istiyor.</p><p>Mesaj: {{customer_message}}</p><p><strong>5 dakika içinde</strong> yanıtlamazsanız talep otomatik iptal olur.</p><p><a href="{{panel_url}}" style="display:inline-block;background:#d4a574;color:#1a1410;padding:12px 24px;text-decoration:none;border-radius:8px;font-weight:bold;">Panele Git</a></p>'),
('71000000-0000-4000-8000-000000000111','70000000-0000-4000-8000-000000000009','en','Instant Session Request','You have an instant session request - {{customer_name}}','<p>Hello {{consultant_name}},</p><p><strong>{{customer_name}}</strong> wants to speak with you <strong>right now</strong>.</p><p>Message: {{customer_message}}</p><p>If you do not respond within <strong>5 minutes</strong>, the request will be cancelled automatically.</p><p><a href="{{panel_url}}" style="display:inline-block;background:#d4a574;color:#1a1410;padding:12px 24px;text-decoration:none;border-radius:8px;font-weight:bold;">Open Panel</a></p>'),
('71000000-0000-4000-8000-000000000112','70000000-0000-4000-8000-000000000009','de','Sofort-Sitzungsanfrage','Sie haben eine Sofort-Sitzungsanfrage - {{customer_name}}','<p>Hallo {{consultant_name}},</p><p><strong>{{customer_name}}</strong> möchte <strong>jetzt sofort</strong> mit Ihnen sprechen.</p><p>Nachricht: {{customer_message}}</p><p>Wenn Sie nicht innerhalb von <strong>5 Minuten</strong> antworten, wird die Anfrage automatisch storniert.</p><p><a href="{{panel_url}}" style="display:inline-block;background:#d4a574;color:#1a1410;padding:12px 24px;text-decoration:none;border-radius:8px;font-weight:bold;">Panel öffnen</a></p>'),
('71000000-0000-4000-8000-00000000000a','70000000-0000-4000-8000-00000000000a','tr','Anlık Görüşme Talebiniz İptal Oldu','Anlık görüşme talebiniz zaman aşımına uğradı','<p>Merhaba {{customer_name}},</p><p>Anlık görüşme talebiniz <strong>5 dakika içinde danışmandan yanıt alamadığı için</strong> otomatik iptal edildi.</p><p>Başka bir danışmanla denemek isterseniz:</p><p><a href="{{consultants_url}}" style="display:inline-block;background:#d4a574;color:#1a1410;padding:12px 24px;text-decoration:none;border-radius:8px;font-weight:bold;">Danışmanları Gör</a></p>'),
('71000000-0000-4000-8000-000000000113','70000000-0000-4000-8000-00000000000a','en','Instant Session Request Expired','Your instant session request expired','<p>Hello {{customer_name}},</p><p>Your instant session request was cancelled automatically because the consultant did not respond within <strong>5 minutes</strong>.</p><p>You can try another consultant here:</p><p><a href="{{consultants_url}}" style="display:inline-block;background:#d4a574;color:#1a1410;padding:12px 24px;text-decoration:none;border-radius:8px;font-weight:bold;">View Consultants</a></p>'),
('71000000-0000-4000-8000-000000000114','70000000-0000-4000-8000-00000000000a','de','Sofort-Sitzungsanfrage abgelaufen','Ihre Sofort-Sitzungsanfrage ist abgelaufen','<p>Hallo {{customer_name}},</p><p>Ihre Sofort-Sitzungsanfrage wurde automatisch storniert, weil der Berater nicht innerhalb von <strong>5 Minuten</strong> geantwortet hat.</p><p>Sie können es hier mit einem anderen Berater versuchen:</p><p><a href="{{consultants_url}}" style="display:inline-block;background:#d4a574;color:#1a1410;padding:12px 24px;text-decoration:none;border-radius:8px;font-weight:bold;">Berater ansehen</a></p>'),
('71000000-0000-4000-8000-000000000201','70000000-0000-4000-8000-000000000012','tr','Sipariş Alındı','{{site_name}} siparişiniz alındı','<p>Merhaba {{customer_name}},</p><p>{{site_name}} siparişiniz alındı.</p><p>Sipariş No: {{order_number}}</p><p>Tutar: {{final_amount}}</p><p>Durum: {{status}}</p>'),
('71000000-0000-4000-8000-000000000202','70000000-0000-4000-8000-000000000012','en','Order Received','Your {{site_name}} order was received','<p>Hello {{customer_name}},</p><p>Your {{site_name}} order was received.</p><p>Order number: {{order_number}}</p><p>Amount: {{final_amount}}</p><p>Status: {{status}}</p>'),
('71000000-0000-4000-8000-000000000203','70000000-0000-4000-8000-000000000012','de','Bestellung erhalten','Ihre {{site_name}} Bestellung wurde erhalten','<p>Hallo {{customer_name}},</p><p>Ihre {{site_name}} Bestellung wurde erhalten.</p><p>Bestellnummer: {{order_number}}</p><p>Betrag: {{final_amount}}</p><p>Status: {{status}}</p>'),
('71000000-0000-4000-8000-000000000204','70000000-0000-4000-8000-000000000013','tr','Bakiye Yükleme Başarılı','{{site_name}} bakiyeniz güncellendi','<p>Merhaba {{user_name}},</p><p>{{amount}} tutarındaki bakiye yüklemeniz başarıyla tamamlandı.</p><p>Yeni bakiyeniz: {{new_balance}}</p><p>{{site_name}}</p>'),
('71000000-0000-4000-8000-000000000205','70000000-0000-4000-8000-000000000013','en','Deposit Successful','Your {{site_name}} balance was updated','<p>Hello {{user_name}},</p><p>Your deposit of {{amount}} was completed successfully.</p><p>New balance: {{new_balance}}</p><p>{{site_name}}</p>'),
('71000000-0000-4000-8000-000000000206','70000000-0000-4000-8000-000000000013','de','Einzahlung erfolgreich','Ihr {{site_name}} Guthaben wurde aktualisiert','<p>Hallo {{user_name}},</p><p>Ihre Einzahlung über {{amount}} wurde erfolgreich abgeschlossen.</p><p>Neues Guthaben: {{new_balance}}</p><p>{{site_name}}</p>'),
('71000000-0000-4000-8000-000000000207','70000000-0000-4000-8000-000000000014','tr','Destek Yanıtı','Destek talebinize yanıt verildi','<p>Merhaba {{user_name}},</p><p>{{ticket_id}} numaralı destek talebinize yanıt verildi.</p><p>Konu: {{ticket_subject}}</p><p>{{reply_message}}</p><p>{{site_name}}</p>'),
('71000000-0000-4000-8000-000000000208','70000000-0000-4000-8000-000000000014','en','Support Reply','Your support ticket has a reply','<p>Hello {{user_name}},</p><p>Your support ticket {{ticket_id}} has a new reply.</p><p>Subject: {{ticket_subject}}</p><p>{{reply_message}}</p><p>{{site_name}}</p>'),
('71000000-0000-4000-8000-000000000209','70000000-0000-4000-8000-000000000014','de','Support-Antwort','Ihr Support-Ticket hat eine Antwort','<p>Hallo {{user_name}},</p><p>Ihr Support-Ticket {{ticket_id}} hat eine neue Antwort.</p><p>Betreff: {{ticket_subject}}</p><p>{{reply_message}}</p><p>{{site_name}}</p>')
